    It 'handles commits with no features or fixes gracefully' {
        $logContent = "abc1234 docs: update readme`ndef5678 chore: lint"
        $entry = New-ChangelogEntry -Version '1.0.0' -LogContent $logContent
        $entry | Should -Match '## 1.0.0'
