    if ($breaking.Count -gt 0) {
        [void]$sb.AppendLine('### BREAKING CHANGES')
        foreach ($c in $breaking) {
            [void]$sb.AppendLine("- $($c.Message) ($($c.Hash))")
        }
        [void]$sb.AppendLine()
    }

    if ($features.Count -gt 0) {
